/**
 * Dubai Metro MMS Demo Data
 * Realistic fleet simulation: 79 Alstom + 49 Kinki Sharyo = 128 trains
 */

export const ALSTOM_COUNT = 79;
export const KINKI_COUNT = 49;
export const TOTAL_FLEET = ALSTOM_COUNT + KINKI_COUNT; // 128

export type MaintenanceType = 'A' | 'B' | 'C' | 'D';
export type TrainStatus = 'operational' | 'maintenance' | 'standby';

export interface Train {
  id: string;
  name: string;
  fleet: 'Alstom' | 'Kinki Sharyo';
  currentMileageKm: number;
  avgDailyMileageKm: number;
  status: TrainStatus;
  lastMaintenanceKm: Record<MaintenanceType, number>;
  nextMaintenanceDue: Record<MaintenanceType, number>;
}

export interface MaintenanceEvent {
  id: string;
  trainId: string;
  type: MaintenanceType;
  scheduledDate: string;
  durationDays: number;
  status: 'scheduled' | 'in-progress' | 'completed';
  mileageAtService: number;
}

export interface WeeklySchedule {
  weekNumber: number;
  startDate: string;
  endDate: string;
  events: MaintenanceEvent[];
  totalWorkload: number;
  capacityUtilization: number;
}

// Maintenance intervals (km)
export const MAINTENANCE_INTERVALS: Record<MaintenanceType, number> = {
  A: 15000,   // Light inspection every 15,000 km
  B: 60000,   // Medium service every 60,000 km
  C: 180000,  // Heavy overhaul every 180,000 km
  D: 720000,  // Major rebuild every 720,000 km
};

// Duration in days
export const MAINTENANCE_DURATION: Record<MaintenanceType, number> = {
  A: 1,
  B: 3,
  C: 7,
  D: 21,
};

// Generate realistic fleet data
export function generateFleet(): Train[] {
  const trains: Train[] = [];

  // Alstom fleet (older, higher mileage)
  for (let i = 1; i <= ALSTOM_COUNT; i++) {
    const id = `ALT-${String(i).padStart(3, '0')}`;
    const baseMileage = 450000 + Math.floor(Math.random() * 350000); // 450k-800k
    const stagger = i * 12000; // Stagger to avoid clustering
    const currentMileage = baseMileage + stagger;

    trains.push({
      id,
      name: `Alstom ${i}`,
      fleet: 'Alstom',
      currentMileageKm: currentMileage,
      avgDailyMileageKm: 280 + Math.floor(Math.random() * 80), // 280-360 km/day
      status: Math.random() > 0.95 ? 'maintenance' : 'operational',
      lastMaintenanceKm: {
        A: currentMileage - Math.floor(Math.random() * 15000),
        B: currentMileage - Math.floor(Math.random() * 60000),
        C: currentMileage - Math.floor(Math.random() * 180000),
        D: currentMileage - Math.floor(Math.random() * 720000),
      },
      nextMaintenanceDue: {
        A: currentMileage + MAINTENANCE_INTERVALS.A - Math.floor(Math.random() * 5000),
        B: currentMileage + MAINTENANCE_INTERVALS.B - Math.floor(Math.random() * 20000),
        C: currentMileage + MAINTENANCE_INTERVALS.C - Math.floor(Math.random() * 50000),
        D: currentMileage + MAINTENANCE_INTERVALS.D - Math.floor(Math.random() * 200000),
      },
    });
  }

  // Kinki Sharyo fleet (newer, lower mileage)
  for (let i = 1; i <= KINKI_COUNT; i++) {
    const id = `KNK-${String(i).padStart(3, '0')}`;
    const baseMileage = 320000 + Math.floor(Math.random() * 280000); // 320k-600k
    const stagger = i * 8000;
    const currentMileage = baseMileage + stagger;

    trains.push({
      id,
      name: `Kinki ${i}`,
      fleet: 'Kinki Sharyo',
      currentMileageKm: currentMileage,
      avgDailyMileageKm: 260 + Math.floor(Math.random() * 60), // 260-320 km/day
      status: Math.random() > 0.97 ? 'maintenance' : 'operational',
      lastMaintenanceKm: {
        A: currentMileage - Math.floor(Math.random() * 15000),
        B: currentMileage - Math.floor(Math.random() * 60000),
        C: currentMileage - Math.floor(Math.random() * 180000),
        D: currentMileage - Math.floor(Math.random() * 720000),
      },
      nextMaintenanceDue: {
        A: currentMileage + MAINTENANCE_INTERVALS.A - Math.floor(Math.random() * 5000),
        B: currentMileage + MAINTENANCE_INTERVALS.B - Math.floor(Math.random() * 20000),
        C: currentMileage + MAINTENANCE_INTERVALS.C - Math.floor(Math.random() * 50000),
        D: currentMileage + MAINTENANCE_INTERVALS.D - Math.floor(Math.random() * 200000),
      },
    });
  }

  return trains;
}

// Generate weekly schedule for demo
export function generateWeeklySchedule(trains: Train[], weeksAhead = 12): WeeklySchedule[] {
  const schedules: WeeklySchedule[] = [];
  const today = new Date();

  for (let week = 0; week < weeksAhead; week++) {
    const startDate = new Date(today);
    startDate.setDate(today.getDate() + week * 7);

    const endDate = new Date(startDate);
    endDate.setDate(startDate.getDate() + 6);

    const events: MaintenanceEvent[] = [];
    let totalWorkload = 0;

    // Simulate ~15-25 maintenance events per week
    const eventsPerWeek = 15 + Math.floor(Math.random() * 10);
    const shuffledTrains = [...trains].sort(() => Math.random() - 0.5);

    for (let i = 0; i < eventsPerWeek && i < shuffledTrains.length; i++) {
      const train = shuffledTrains[i];
      const types: MaintenanceType[] = ['A', 'A', 'A', 'B', 'B', 'C']; // Weighted towards A
      const type = types[Math.floor(Math.random() * types.length)];
      const duration = MAINTENANCE_DURATION[type];

      const eventDate = new Date(startDate);
      eventDate.setDate(startDate.getDate() + Math.floor(Math.random() * 5));

      events.push({
        id: `EVT-${week}-${i}`,
        trainId: train.id,
        type,
        scheduledDate: eventDate.toISOString().split('T')[0],
        durationDays: duration,
        status: week < 2 ? 'completed' : week < 4 ? 'in-progress' : 'scheduled',
        mileageAtService: train.currentMileageKm + (week * train.avgDailyMileageKm * 7),
      });

      totalWorkload += duration;
    }

    // Capacity: 30 train-days per week (5 bays × 6 days)
    const capacity = 30;

    schedules.push({
      weekNumber: week + 1,
      startDate: startDate.toISOString().split('T')[0],
      endDate: endDate.toISOString().split('T')[0],
      events,
      totalWorkload,
      capacityUtilization: Math.round((totalWorkload / capacity) * 100),
    });
  }

  return schedules;
}

// Dashboard KPIs
export function calculateKPIs(trains: Train[], schedules: WeeklySchedule[]) {
  const operational = trains.filter(t => t.status === 'operational').length;
  const inMaintenance = trains.filter(t => t.status === 'maintenance').length;

  const avgMileage = Math.round(
    trains.reduce((sum, t) => sum + t.currentMileageKm, 0) / trains.length
  );

  const upcomingEvents = schedules
    .slice(0, 4)
    .flatMap(s => s.events)
    .filter(e => e.status === 'scheduled');

  const avgUtilization = Math.round(
    schedules.reduce((sum, s) => sum + s.capacityUtilization, 0) / schedules.length
  );

  // Trains needing attention (within 5000km of maintenance)
  const urgentCount = trains.filter(t => {
    const kmToNextA = t.nextMaintenanceDue.A - t.currentMileageKm;
    return kmToNextA < 5000;
  }).length;

  return {
    totalFleet: trains.length,
    operational,
    inMaintenance,
    standby: trains.length - operational - inMaintenance,
    avgMileage,
    upcomingEventsCount: upcomingEvents.length,
    avgUtilization,
    urgentCount,
    fleetAvailability: Math.round((operational / trains.length) * 100),
  };
}

// Pre-generated data for consistent demo
let cachedFleet: Train[] | null = null;
let cachedSchedules: WeeklySchedule[] | null = null;

export function getFleet(): Train[] {
  if (!cachedFleet) {
    cachedFleet = generateFleet();
  }
  return cachedFleet;
}

export function getSchedules(): WeeklySchedule[] {
  if (!cachedSchedules) {
    cachedSchedules = generateWeeklySchedule(getFleet(), 12);
  }
  return cachedSchedules;
}

export function getKPIs() {
  return calculateKPIs(getFleet(), getSchedules());
}

