import { getFleet, getKPIs, getSchedules, type Train } from "../lib/demo-data";

export function meta() {
  return [
    { title: "Dashboard | Dubai Metro MMS" },
    { name: "description", content: "Mileage Management System Dashboard" },
  ];
}

function KPICard({
  title,
  value,
  subtitle,
  trend,
  color = "blue",
}: {
  title: string;
  value: string | number;
  subtitle?: string;
  trend?: { value: number; label: string };
  color?: "blue" | "green" | "yellow" | "red";
}) {
  const colorClasses = {
    blue: "bg-blue-50 border-blue-200",
    green: "bg-green-50 border-green-200",
    yellow: "bg-yellow-50 border-yellow-200",
    red: "bg-red-50 border-red-200",
  };

  const trendColors = {
    blue: "text-blue-600",
    green: "text-green-600",
    yellow: "text-yellow-600",
    red: "text-red-600",
  };

  return (
    <div
      className={`p-6 rounded-xl border-2 ${colorClasses[color]} transition-transform hover:scale-[1.02]`}
    >
      <p className="text-sm font-medium text-gray-600 mb-1">{title}</p>
      <p className="text-3xl font-bold text-gray-900">{value}</p>
      {subtitle && <p className="text-sm text-gray-500 mt-1">{subtitle}</p>}
      {trend && (
        <p className={`text-sm font-medium mt-2 ${trendColors[color]}`}>
          {trend.value > 0 ? "↑" : "↓"} {Math.abs(trend.value)}% {trend.label}
        </p>
      )}
    </div>
  );
}

function StatusBadge({ status }: { status: Train["status"] }) {
  const styles = {
    operational: "bg-green-100 text-green-800",
