        </div>
      </div>

      {/* Capacity Chart Placeholder */}
      <div className="bg-white rounded-xl border border-gray-200 p-6">
        <h2 className="font-semibold text-gray-900 mb-4">
          12-Week Capacity Forecast
        </h2>
        <div className="flex items-end gap-2 h-40">
          {schedules.map((week) => (
            <div
              key={week.weekNumber}
              className="flex-1 flex flex-col items-center gap-2"
            >
              <div
                className={`w-full rounded-t transition-all ${
                  week.capacityUtilization > 90
                    ? "bg-red-400"
                    : week.capacityUtilization > 70
                      ? "bg-yellow-400"
                      : "bg-blue-400"
                }`}
                style={{ height: `${week.capacityUtilization}%` }}
              />
              <span className="text-xs text-gray-500">W{week.weekNumber}</span>
            </div>
          ))}
        </div>
        <div className="flex items-center gap-6 mt-4 text-sm">
