            <span className="w-3 h-3 rounded bg-blue-400" /> Normal
          </span>
          <span className="flex items-center gap-2">
            <span className="w-3 h-3 rounded bg-yellow-400" /> High
          </span>
          <span className="flex items-center gap-2">
            <span className="w-3 h-3 rounded bg-red-400" /> Critical
          </span>
        </div>
      </div>
    </div>
  );
}

