input.content:
import { useState } from "react";
import { getFleet, type Train, ALSTOM_COUNT, KINKI_COUNT } from "../lib/demo-data";

export function meta() {
  return [
    { title: "Fleet | Dubai Metro MMS" },
    { name: "description", content: "Fleet Management Overview" },
  ];
}

function StatusBadge({ status }: { status: Train["status"] }) {
  const styles = {
    operational: "bg-green-100 text-green-800 border-green-200",
    maintenance: "bg-yellow-100 text-yellow-800 border-yellow-200",
    standby: "bg-gray-100 text-gray-800 border-gray-200",
  };

  return (
    <span
      className={`px-2.5 py-1 rounded-full text-xs font-medium border ${styles[status]}`}
    >
      {status}
    </span>
  );
}

function FleetBadge({ fleet }: { fleet: Train["fleet"] }) {
  return (
    <span
      className={`px-2.5 py-1 rounded-full text-xs font-medium ${
        fleet === "Alstom"
          ? "bg-blue-100 text-blue-800 border border-blue-200"
          : "bg-purple-100 text-purple-800 border border-purple-200"
      }`}
    >
      {fleet}
    </span>
  );
}

export default function Fleet() {
  const fleet = getFleet();
  const [filter, setFilter] = useState<"all" | "Alstom" | "Kinki Sharyo">("all");
  const [statusFilter, setStatusFilter] = useState<"all" | Train["status"]>("all");
  const [searchQuery, setSearchQuery] = useState("");

  const filteredFleet = fleet.filter((train) => {
    if (filter !== "all" && train.fleet !== filter) return false;
    if (statusFilter !== "all" && train.status !== statusFilter) return false;
    if (searchQuery && !train.id.toLowerCase().includes(searchQuery.toLowerCase()))
      return false;
    return true;
  });

  const stats = {
    total: fleet.length,
    alstom: ALSTOM_COUNT,
    kinki: KINKI_COUNT,
    operational: fleet.filter((t) => t.status === "operational").length,
    maintenance: fleet.filter((t) => t.status === "maintenance").length,
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Fleet Overview</h1>
          <p className="text-gray-500">
            Manage and monitor your complete train fleet
          </p>
        </div>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
        <div className="bg-white p-4 rounded-xl border border-gray-200">
          <p className="text-sm text-gray-500">Total Fleet</p>
          <p className="text-2xl font-bold text-gray-900">{stats.total}</p>
        </div>
        <div className="bg-blue-50 p-4 rounded-xl border border-blue-200">
          <p className="text-sm text-blue-600">Alstom</p>
          <p className="text-2xl font-bold text-blue-900">{stats.alstom}</p>
        </div>
        <div className="bg-purple-50 p-4 rounded-xl border border-purple-200">
          <p className="text-sm text-purple-600">Kinki Sharyo</p>
          <p className="text-2xl font-bold text-purple-900">{stats.kinki}</p>
        </div>
        <div className="bg-green-50 p-4 rounded-xl border border-green-200">
          <p className="text-sm text-green-600">Operational</p>
          <p className="text-2xl font-bold text-green-900">{stats.operational}</p>
        </div>
        <div className="bg-yellow-50 p-4 rounded-xl border border-yellow-200">
          <p className="text-sm text-yellow-600">In Maintenance</p>
          <p className="text-2xl font-bold text-yellow-900">{stats.maintenance}</p>
        </div>
      </div>

      {/* Filters */}
      <div className="bg-white p-4 rounded-xl border border-gray-200">
        <div className="flex flex-wrap items-center gap-4">
          <div>
            <label className="block text-xs text-gray-500 mb-1">Search</label>
            <input
              type="text"
              placeholder="Search by ID..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
            />
          </div>

          <div>
            <label className="block text-xs text-gray-500 mb-1">Fleet Type</label>
            <select
              value={filter}
              onChange={(e) => setFilter(e.target.value as typeof filter)}
              className="px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500"
            >
              <option value="all">All Fleets</option>
              <option value="Alstom">Alstom</option>
              <option value="Kinki Sharyo">Kinki Sharyo</option>
            </select>
          </div>

          <div>
            <label className="block text-xs text-gray-500 mb-1">Status</label>
            <select
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value as typeof statusFilter)}
              className="px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500"
            >
              <option value="all">All Status</option>
              <option value="operational">Operational</option>
              <option value="maintenance">Maintenance</option>
              <option value="standby">Standby</option>
            </select>
          </div>

          <div className="ml-auto text-sm text-gray-500">
            Showing {filteredFleet.length} of {fleet.length} trains
          </div>
        </div>
      </div>

      {/* Fleet Table */}
      <div className="bg-white rounded-xl border border-gray-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-gray-50 border-b border-gray-200">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Train ID
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Fleet
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Status
                </th>
                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Current Mileage
                </th>
                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Avg Daily
                </th>
                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Next A-Check
                </th>
                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Next B-Check
                </th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filteredFleet.slice(0, 50).map((train) => {
                const kmToA = train.nextMaintenanceDue.A - train.currentMileageKm;
                const kmToB = train.nextMaintenanceDue.B - train.currentMileageKm;
                const daysToA = Math.round(kmToA / train.avgDailyMileageKm);

                return (
                  <tr key={train.id} className="hover:bg-gray-50">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div
                          className={`w-8 h-8 rounded-lg flex items-center justify-center ${
                            train.fleet === "Alstom"
                              ? "bg-blue-100 text-blue-700"
                              : "bg-purple-100 text-purple-700"
                          }`}
                        >
                          🚇
                        </div>
                        <span className="font-medium text-gray-900">
                          {train.id}
                        </span>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <FleetBadge fleet={train.fleet} />
                    </td>
                    <td className="px-6 py-4">
                      <StatusBadge status={train.status} />
                    </td>
