import { useState } from "react";
import {
  getSchedules,
  getFleet,
  type WeeklySchedule,
  type MaintenanceEvent,
  type MaintenanceType,
  MAINTENANCE_DURATION,
} from "../lib/demo-data";

export function meta() {
  return [
    { title: "Calendar | Dubai Metro MMS" },
    { name: "description", content: "Maintenance Schedule Calendar" },
  ];
}

const typeColors: Record<MaintenanceType, string> = {
  A: "bg-green-100 text-green-800 border-green-300",
  B: "bg-blue-100 text-blue-800 border-blue-300",
  C: "bg-orange-100 text-orange-800 border-orange-300",
  D: "bg-red-100 text-red-800 border-red-300",
};

const typeLabels: Record<MaintenanceType, string> = {
  A: "A-Check (Light)",
  B: "B-Check (Medium)",
  C: "C-Check (Heavy)",
  D: "D-Check (Major)",
};

function WeekCard({
  week,
  onClick,
}: {
  week: WeeklySchedule;
  onClick: () => void;
}) {
  const eventsByType = {
    A: week.events.filter((e) => e.type === "A").length,
    B: week.events.filter((e) => e.type === "B").length,
    C: week.events.filter((e) => e.type === "C").length,
    D: week.events.filter((e) => e.type === "D").length,
  };

  const utilizationColor =
    week.capacityUtilization > 90
      ? "text-red-600 bg-red-50"
      : week.capacityUtilization > 70
        ? "text-yellow-600 bg-yellow-50"
        : "text-green-600 bg-green-50";

  return (
    <div
      onClick={onClick}
      className="bg-white rounded-xl border border-gray-200 p-4 hover:shadow-lg hover:border-blue-300 transition-all cursor-pointer"
    >
      <div className="flex items-center justify-between mb-3">
        <div>
          <h3 className="font-semibold text-gray-900">Week {week.weekNumber}</h3>
          <p className="text-xs text-gray-500">
            {new Date(week.startDate).toLocaleDateString("en-GB", {
              day: "numeric",
              month: "short",
            })}{" "}
            -{" "}
            {new Date(week.endDate).toLocaleDateString("en-GB", {
              day: "numeric",
              month: "short",
            })}
          </p>
        </div>
        <span
          className={`px-2 py-1 rounded-full text-xs font-bold ${utilizationColor}`}
        >
          {week.capacityUtilization}%
        </span>
      </div>

      {/* Capacity Bar */}
      <div className="mb-3">
        <div className="h-2 bg-gray-100 rounded-full overflow-hidden">
          <div
            className={`h-full transition-all ${
              week.capacityUtilization > 90
                ? "bg-red-500"
                : week.capacityUtilization > 70
                  ? "bg-yellow-500"
                  : "bg-green-500"
            }`}
            style={{ width: `${Math.min(week.capacityUtilization, 100)}%` }}
          />
        </div>
        <p className="text-xs text-gray-500 mt-1">
          {week.totalWorkload} / 30 train-days
        </p>
      </div>

      {/* Event Badges */}
      <div className="flex flex-wrap gap-1">
        {(["A", "B", "C", "D"] as MaintenanceType[]).map((type) =>
          eventsByType[type] > 0 ? (
            <span
              key={type}
              className={`px-2 py-0.5 rounded text-xs font-medium border ${typeColors[type]}`}
            >
              {eventsByType[type]}× {type}
            </span>
          ) : null
        )}
      </div>
    </div>
  );
}

function WeekModal({
  week,
  onClose,
}: {
  week: WeeklySchedule;
  onClose: () => void;
}) {
  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-2xl max-w-2xl w-full max-h-[80vh] overflow-hidden">
        <div className="px-6 py-4 border-b border-gray-200 flex items-center justify-between">
          <div>
            <h2 className="text-xl font-bold text-gray-900">
              Week {week.weekNumber} Schedule
            </h2>
            <p className="text-sm text-gray-500">
              {new Date(week.startDate).toLocaleDateString("en-GB", {
                weekday: "long",
                day: "numeric",
                month: "long",
              })}{" "}
              -{" "}
              {new Date(week.endDate).toLocaleDateString("en-GB", {
                weekday: "long",
                day: "numeric",
                month: "long",
              })}
            </p>
          </div>
          <button
            onClick={onClose}
            className="p-2 hover:bg-gray-100 rounded-lg transition-colors"
          >
            ✕
          </button>
        </div>

        <div className="p-6 overflow-y-auto max-h-[60vh]">
          <div className="grid grid-cols-3 gap-4 mb-6">
            <div className="bg-gray-50 p-4 rounded-lg">
              <p className="text-sm text-gray-500">Total Events</p>
              <p className="text-2xl font-bold">{week.events.length}</p>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg">
              <p className="text-sm text-gray-500">Workload</p>
              <p className="text-2xl font-bold">{week.totalWorkload} days</p>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg">
              <p className="text-sm text-gray-500">Utilization</p>
              <p className="text-2xl font-bold">{week.capacityUtilization}%</p>
            </div>
          </div>

          <h3 className="font-semibold text-gray-900 mb-3">
            Scheduled Maintenance
          </h3>
          <div className="space-y-2">
            {week.events.map((event) => (
              <div
                key={event.id}
                className="flex items-center justify-between p-3 bg-gray-50 rounded-lg hover:bg-gray-100"
              >
                <div className="flex items-center gap-3">
                  <span
                    className={`w-8 h-8 rounded-lg flex items-center justify-center font-bold border ${typeColors[event.type]}`}
                  >
                    {event.type}
                  </span>
                  <div>
                    <p className="font-medium text-gray-900">{event.trainId}</p>
                    <p className="text-xs text-gray-500">
                      {typeLabels[event.type]} • {event.durationDays} day
                      {event.durationDays > 1 ? "s" : ""}
                    </p>
                  </div>
                </div>
                <div className="text-right">
                  <p className="text-sm font-medium text-gray-900">
                    {new Date(event.scheduledDate).toLocaleDateString("en-GB", {
                      weekday: "short",
                      day: "numeric",
                    })}
                  </p>
                  <p className="text-xs text-gray-500">
                    {event.mileageAtService.toLocaleString()} km
                  </p>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="px-6 py-4 border-t border-gray-200 bg-gray-50 flex justify-end gap-2">
          <button
            onClick={onClose}
            className="px-4 py-2 text-gray-700 hover:bg-gray-200 rounded-lg transition-colors"
          >
            Close
          </button>
        </div>
      </div>
    </div>
  );
}

export default function Calendar() {
  const schedules = getSchedules();
  const [selectedWeek, setSelectedWeek] = useState<WeeklySchedule | null>(null);
  const [typeFilter, setTypeFilter] = useState<MaintenanceType | "all">("all");

  const filteredSchedules = schedules.map((week) => ({
    ...week,
    events:
      typeFilter === "all"
        ? week.events
        : week.events.filter((e) => e.type === typeFilter),
  }));

  // Summary stats
  const totalEvents = schedules.reduce((sum, w) => sum + w.events.length, 0);
  const avgUtilization = Math.round(
    schedules.reduce((sum, w) => sum + w.capacityUtilization, 0) / schedules.length
  );

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">
            Maintenance Calendar
          </h1>
          <p className="text-gray-500">
            12-week maintenance schedule overview
          </p>
        </div>

        <div className="flex items-center gap-2">
          <button
            onClick={() => alert("Export coming soon!")}
            className="px-4 py-2 bg-white border border-gray-300 rounded-lg text-sm font-medium hover:bg-gray-50 flex items-center gap-2"
          >
            📥 Export Excel
          </button>
          <button
            onClick={() => alert("Maximo export coming soon!")}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-medium hover:bg-blue-700 flex items-center gap-2"
          >
            📤 Export to Maximo
          </button>
        </div>
      </div>

      {/* Summary Stats */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <div className="bg-white p-4 rounded-xl border border-gray-200">
          <p className="text-sm text-gray-500">Planning Horizon</p>
          <p className="text-2xl font-bold text-gray-900">12 weeks</p>
        </div>
        <div className="bg-white p-4 rounded-xl border border-gray-200">
          <p className="text-sm text-gray-500">Total Events</p>
          <p className="text-2xl font-bold text-gray-900">{totalEvents}</p>
        </div>
        <div className="bg-white p-4 rounded-xl border border-gray-200">
          <p className="text-sm text-gray-500">Avg Utilization</p>
          <p className="text-2xl font-bold text-gray-900">{avgUtilization}%</p>
        </div>
        <div className="bg-white p-4 rounded-xl border border-gray-200">
          <p className="text-sm text-gray-500">Optimization Status</p>
          <p className="text-lg font-bold text-green-600">✓ Balanced</p>
        </div>
      </div>

      {/* Filter */}
      <div className="bg-white p-4 rounded-xl border border-gray-200">
        <div className="flex items-center gap-4">
          <span className="text-sm text-gray-500">Filter by type:</span>
          <div className="flex gap-2">
            <button
              onClick={() => setTypeFilter("all")}
              className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${
                typeFilter === "all"
                  ? "bg-gray-900 text-white"
                  : "bg-gray-100 text-gray-700 hover:bg-gray-200"
              }`}
            >
              All
            </button>
            {(["A", "B", "C", "D"] as MaintenanceType[]).map((type) => (
              <button
                key={type}
                onClick={() => setTypeFilter(type)}
                className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors border ${
                  typeFilter === type
                    ? typeColors[type]
                    : "bg-gray-100 text-gray-700 hover:bg-gray-200 border-transparent"
                }`}
              >
                {type}-Check
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Legend */}
      <div className="flex items-center gap-6 text-sm">
        <span className="text-gray-500">Legend:</span>
        {(["A", "B", "C", "D"] as MaintenanceType[]).map((type) => (
          <span key={type} className="flex items-center gap-2">
            <span
              className={`w-6 h-6 rounded flex items-center justify-center text-xs font-bold border ${typeColors[type]}`}
            >
              {type}
            </span>
            <span className="text-gray-600">
              {typeLabels[type]} ({MAINTENANCE_DURATION[type]}d)
            </span>
          </span>
        ))}
      </div>

      {/* Calendar Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 gap-4">
        {filteredSchedules.map((week) => (
          <WeekCard
            key={week.weekNumber}
            week={week}
            onClick={() => setSelectedWeek(schedules[week.weekNumber - 1])}
          />
        ))}
      </div>

      {/* Modal */}
      {selectedWeek && (
        <WeekModal week={selectedWeek} onClose={() => setSelectedWeek(null)} />
      )}
    </div>
  );
}

